package src.org.apache.nutch.tools;

public class CommonCrawlFormatFactory { public static CommonCrawlFormat getCommonCrawlFormat ( String formatType , String url , Content content , Metadata metadata , Configuration nutchConf , CommonCrawlConfig config ) throws IOException { if ( formatType == null ) { return null ; } if ( formatType . equalsIgnoreCase ( "jackson" ) ) { return new CommonCrawlFormatJackson ( url , content , metadata , nutchConf , config ) ; } else if ( formatType . equalsIgnoreCase ( "jettinson" ) ) { return new CommonCrawlFormatJettinson ( url , content , metadata , nutchConf , config ) ; } else if ( formatType . equalsIgnoreCase ( "simple" ) ) { return new CommonCrawlFormatSimple ( url , content , metadata , nutchConf , config ) ; } return null ; } public static CommonCrawlFormat getCommonCrawlFormat ( String formatType , Configuration nutchConf , CommonCrawlConfig config ) throws IOException { if ( formatType . equalsIgnoreCase ( "WARC" ) ) { return new CommonCrawlFormatWARC ( nutchConf , config ) ; } if ( formatType . equalsIgnoreCase ( "JACKSON" ) ) { return new CommonCrawlFormatJackson ( nutchConf , config ) ; } return null ; } }